use std::io::*;

fn reads<T: std::str::FromStr>(i: &mut StdinLock) -> Vec<T> {
    let mut s = String::new();
    i.by_ref().read_line(&mut s).ok();
    s.trim()
        .split_whitespace()
        .map(|e| e.parse().ok().unwrap())
        .collect()
}

fn gcd_worker(a: u64, b: u64) -> u64 {
    match b {
        0 => a,
        _ => gcd_worker(b, a % b),
    }
}

fn gcd(a: u64, b: u64) -> u64 {
    let greater = std::cmp::max(a, b);
    let smaller = std::cmp::min(a, b);
    gcd_worker(greater, smaller)
}

fn main() {
    // initialize stdin
    let sin = std::io::stdin();
    let mut sin = sin.lock();
    let sin = &mut sin;

    let params: Vec<u64> = reads(sin);

    let a = params[0];
    let b = params[1];
    let heap = params[2];

    let mut remain = heap;
    let mut turn_of_antisimon = false;

    loop {
        let have_to_take = gcd(if turn_of_antisimon { b } else { a }, remain);
        if remain < have_to_take {
            break;
        }

        remain = remain - have_to_take;
        turn_of_antisimon = !turn_of_antisimon;
    }

    println!("{}", if turn_of_antisimon { 0 } else { 1 });
}
